+  constructor(stream: MockStream) {
+    this.stream = stream;
+    this.lastRequest = null;
+    this.responses = {
+      stream: async (body: OracleRequestBody) => {
+        this.lastRequest = body;
+        return this.stream;
+      },
+    };
+  }
